function getShowcaseItems() {
  const hourSlot = Math.floor(Date.now() / 3600000); // muda a cada hora
  const seed     = hourSlot % SHOWCASE_POOL.length;
  // Pega 4 itens rotativos baseado na hora atual
  const items = [];
  for (let i = 0; i < 4; i++) {
    items.push(SHOWCASE_POOL[(seed + i) % SHOWCASE_POOL.length]);
  }
  return items;
}

// ══════════════════════════════════════════════════════════════
// SAVE SYSTEM – Anti-bug de moedas
// ══════════════════════════════════════════════════════════════
function _computeHash(save) {
  // Hash simples mas eficaz: baseado em ouro + xp + segredo
  const raw = `${Math.floor(save.gold)}|${Math.floor(save.xp)}|${save.totalGoldEarned||0}|${save.totalGoldSpent||0}|${_SECRET}`;
  let h = 0;
  for (let i = 0; i < raw.length; i++) {
    h = ((h << 5) - h + raw.charCodeAt(i)) | 0;
  }
  return (h >>> 0).toString(36);
}

function _encodeSave(data) {
  try {
    const json = JSON.stringify(data);
    return btoa(encodeURIComponent(json).replace(/%([0-9A-F]{2})/g, (_, p1) =>
      String.fromCharCode('0x' + p1)));
  } catch(e) {
    return JSON.stringify(data);
  }
}

function _decodeSave(raw) {
  try {
    // Tentar decodificação base64 primeiro
    const json = decodeURIComponent(Array.from(atob(raw), c =>
      '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2)).join(''));
    return JSON.parse(json);
  } catch(e) {
    // Fallback: JSON puro (compatibilidade)
    try { return JSON.parse(raw); } catch(e2) { return null; }
  }
}

function createDefaultSave(name) {
  return {
    version:          3,
    playerName:       name || "Guerreiro",
    gold:             500,
    xp:               0,
    xpp:              0,
    wins:             0,
    losses:           0,
    totalBattles:     0,
    vault:            [],
    vaultLimit:       50,
    deck:             [],
    activeBoosts:     [],
    boostUsedToday:   {},
    starterPacksLeft: 5,
    dailyBattles:     0,
    dailyWins:        0,
    dailyPacksOpened: 0,
    dailyMissions:    {},
    lastDailyReset:   new Date().toDateString(),
    loginStreak:      0,
    lastLoginDate:    "",
    loginRewardDay:   0,
    loginClaimedToday:false,
    events:           {},
    createdAt:        Date.now(),
    isAdmin:          false,
    // Anti-bug de moeda
    totalGoldEarned:  500,
    totalGoldSpent:   0,
    goldHash:         "",
    lastSaveTime:     Date.now(),
    // Perfil
    profileFrame:     "",
    profileTitle:     "",
    profileAvatar:    "",
    profileEffect:    "",
    profileBadge:     "", // selo (ex: verificado) equipado no topo do perfil
    profileCards:     [], // até 3 cartas exibidas no perfil
    ownedProfileItems:[],
    // Espaço extra comprado na loja (once per day)
    lastVaultExpand:  "",
    // Criador de Conteúdo Verificado
    isVerifiedCreator:    false,
    verifiedSince:        0,
    // Correio (presentes diários via correio.html)
    correioInbox:         [],  // cartas recebidas (claimed:false/true)
    lastCorreioGenerated: "",  // data (toDateString) da última carta gerada
    receivedAdminMsgs:    [],  // ids das mensagens de admin (ADMIN_MESSAGES) já entregues a esse jogador
  };
}

function getOrCreateSave() {
  let raw = localStorage.getItem(SAVE_KEY);
  let save = null;

  if (raw) {
    save = _decodeSave(raw);
  }

  // Migração v2 → v3
  if (!save) {
    const oldRaw = localStorage.getItem(SAVE_KEY_V2);
    if (oldRaw) {
      try {
        save = JSON.parse(oldRaw);
        save.version = 3;
      } catch(e) { save = null; }
    }
  }

  if (!save) {
    // Novo jogador
    const name = prompt("👤 Bem-vindo ao Card Fight!\nDigite seu nome de jogador:") || "Guerreiro";
    save = createDefaultSave(name.slice(0, 20));
    save.goldHash = _computeHash(save);
    writeSave(save);
    return save;
  }

  // Garantir campos novos (compatibilidade)
  save.version          = save.version          || 3;
  save.totalGoldEarned  = save.totalGoldEarned  || save.gold || 0;
  save.totalGoldSpent   = save.totalGoldSpent   || 0;
  save.ownedProfileItems= save.ownedProfileItems|| [];
  save.profileFrame     = save.profileFrame     || "";
  save.profileTitle     = save.profileTitle     || "";
  save.profileAvatar    = save.profileAvatar    || "";
  save.profileEffect    = save.profileEffect    || "";
  save.profileCards     = save.profileCards     || [];
  save.lastVaultExpand  = save.lastVaultExpand  || "";
  save.vaultLimit       = save.vaultLimit       || 50;
  save.activeBoosts     = save.activeBoosts     || [];
  save.boostUsedToday   = save.boostUsedToday   || {};
  save.events           = save.events           || {};
  save.dailyMissions    = save.dailyMissions    || {};
  save.loginClaimedToday= save.loginClaimedToday || false;
  save.profileBadge     = save.profileBadge     || "";
  save.isVerifiedCreator= save.isVerifiedCreator || false;
  save.verifiedSince    = save.verifiedSince     || 0;
  save.correioInbox     = save.correioInbox      || [];
  save.lastCorreioGenerated = save.lastCorreioGenerated || "";
  save.receivedAdminMsgs = save.receivedAdminMsgs || [];

  // ── Anti-bug de moeda: verificação de integridade ──────────
  if (save.goldHash) {
    const expected = _computeHash(save);
    if (save.goldHash !== expected) {
      // Hash diverge → possível manipulação. Recalcula gold pelo ledger.
      const computedGold = (save.totalGoldEarned || 0) - (save.totalGoldSpent || 0);
      if (computedGold >= 0 && computedGold < save.gold * 5) {
        // Diferença suspeita mas dentro do razoável → usa mínimo seguro
        save.gold = Math.min(save.gold, Math.max(0, computedGold));
      } else {
        save.gold = Math.max(0, computedGold);
      }
      save.goldHash = _computeHash(save);
    }
  } else {
    // Primeiro acesso com sistema novo: gera hash
    save.goldHash = _computeHash(save);
  }

  // Reset diário
  const today = new Date().toDateString();
  if (save.lastDailyReset !== today) {
    save.dailyBattles    = 0;
    save.dailyWins       = 0;
    save.dailyPacksOpened= 0;
    save.boostUsedToday  = {};
    save.lastDailyReset  = today;
    save.loginClaimedToday = false;
    // FIX: as Missões Diárias (DAILY_MISSIONS / save.dailyMissions) nunca
    // eram limpas aqui — por isso ficavam com o mesmo progresso/"coletado"
    // para sempre, em vez de resetar toda meia-noite junto com o resto.
    save.dailyMissions   = {};
    writeSave(save);
  }

  return save;
}

function writeSave(save) {
  // Sempre atualiza o hash antes de salvar
  save.goldHash    = _computeHash(save);
  save.lastSaveTime= Date.now();
  try {
    const encoded = _encodeSave(save);
    localStorage.setItem(SAVE_KEY, encoded);
  } catch(e) {
    // Fallback não codificado
    localStorage.setItem(SAVE_KEY, JSON.stringify(save));
  }
}

// Gasta ouro com rastreamento para o ledger
function spendGold(save, amount) {
  if (save.gold < amount) return false;
  save.gold         -= amount;
  save.totalGoldSpent= (save.totalGoldSpent||0) + amount;
  return true;
}

// Ganha ouro com rastreamento
function earnGold(save, amount) {
  save.gold         += amount;
  save.totalGoldEarned= (save.totalGoldEarned||0) + amount;
}

function startAutoSave(getSaveFn, interval = 15000) {
  setInterval(() => {
    const s = getSaveFn();
    if (s) writeSave(s);
  }, interval);
}

// ══════════════════════════════════════════════════════════════
// FUNÇÕES DE CARTAS
// ══════════════════════════════════════════════════════════════
function getCardById(id) {
  return ALL_CARDS.find(c => c.id === id) || null;
}

function getCardsByRarity(rarity) {
  return ALL_CARDS.filter(c => c.rarity === rarity);
}

function getHandFromVault(vault) {
  if (vault.length === 0) return [];
  const shuffled = [...vault].sort(() => Math.random() - 0.5);
  const hand = shuffled.slice(0, Math.min(10, vault.length));
  return hand.map(id => getCardById(id)).filter(Boolean);
}

function getBotHand(botXpp) {
  // Bot recebe cartas baseadas no XPP dele.
  // Bots nos ranks iniciais usam majoritariamente cartas COMMON para facilitar
  // a entrada de novos jogadores no jogo.
  const rank = getRank(botXpp);
  const rankIdx = RANKS.indexOf(rank);

  // Ranks 0-1: bot usa quase só COMMON (90% comum, 10% rara) → muito fácil
  if (rankIdx < 2) {
    const commons = ALL_CARDS.filter(c => c.rarity === "COMMON");
    const rares   = ALL_CARDS.filter(c => c.rarity === "RARE");
    const hand = [];
    for (let i = 0; i < 10; i++) {
      const pool = (Math.random() < 0.10 && rares.length > 0) ? rares : commons;
      hand.push(pool[Math.floor(Math.random() * pool.length)]);
    }
    return hand;
  }

  // Ranks 2-3: mix leve de COMMON + RARE
  if (rankIdx < 4) {
    const commons = ALL_CARDS.filter(c => c.rarity === "COMMON");
    const rares   = ALL_CARDS.filter(c => c.rarity === "RARE");
    const hand = [];
    for (let i = 0; i < 10; i++) {
      const pool = (Math.random() < 0.30 && rares.length > 0) ? rares : commons;
      hand.push(pool[Math.floor(Math.random() * pool.length)]);
    }
    return hand;
  }

  let pool = [];
  if (rankIdx < 7) {
    pool = ALL_CARDS.filter(c => ["COMMON","RARE"].includes(c.rarity));
  } else if (rankIdx < 11) {
    pool = ALL_CARDS.filter(c => ["COMMON","RARE","EPIC"].includes(c.rarity));
  } else if (rankIdx < 14) {
    pool = ALL_CARDS.filter(c => ["RARE","EPIC","LEGENDARY"].includes(c.rarity));
  } else if (rankIdx < 17) {
    pool = ALL_CARDS.filter(c => ["EPIC","LEGENDARY","MYTHIC"].includes(c.rarity));
  } else {
    pool = ALL_CARDS.filter(c => ["LEGENDARY","MYTHIC","ULTRA_RARE","ORIGENS"].includes(c.rarity));
  }

  if (pool.length === 0) pool = ALL_CARDS;
  const shuffled = [...pool].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, 10);
}

// Abre um pacote e retorna as cartas
function openPack(pack, save) {
  const hasLuck   = save && (save.activeBoosts||[]).some(b => b.type === "luck" && b.endTime > Date.now());
  const luckMult  = hasLuck ? 1.5 : 1;
  const cards     = [];

  for (const targetRarity of pack.rarities) {
    const r = RARITY[targetRarity] || RARITY.COMMON;
    // Com boost de sorte, pode promover raridade
    let chosenRarity = targetRarity;
    if (hasLuck && Math.random() < 0.15 * luckMult) {
      const rarOrder = ["COMMON","RARE","EPIC","LEGENDARY","MYTHIC","ULTRA_RARE","ORIGENS"];
      const curIdx   = rarOrder.indexOf(targetRarity);
      if (curIdx < rarOrder.length - 1) {
        chosenRarity = rarOrder[curIdx + 1];
      }
    }
    const pool = getCardsByRarity(chosenRarity);
    if (pool.length > 0) {
      cards.push(pool[Math.floor(Math.random() * pool.length)]);
    }
  }

  // ⚠️ CORREÇÃO CRÍTICA: as cartas sorteadas precisam ser adicionadas ao
  // cofre do jogador. Antes, openPack() apenas retornava as cartas sem
  // gravá-las em save.vault, então pacotes comprados nunca chegavam ao cofre.
  if (save) {
    if (!save.vault) save.vault = [];
    const vaultLimit = save.vaultLimit || 50;
    for (const card of cards) {
      if (save.vault.length >= vaultLimit) break; // cofre cheio, não recebe mais
      save.vault.push(card.id);
    }
  }

  return cards;
}

// ══════════════════════════════════════════════════════════════
// RANK / LEVEL
// ══════════════════════════════════════════════════════════════
function getRank(xpp) {
  let rank = RANKS[0];
  for (const r of RANKS) {
    if (xpp >= r.xpp) rank = r; else break;
  }
  return rank;
}

function getNextRank(xpp) {
  for (let i = 0; i < RANKS.length; i++) {
    if (xpp < RANKS[i].xpp) return RANKS[i];
  }
  return null;
}

function xpForLevel(level) {
  if (level <= 1) return 0;
  
  // ═══════════════════════════════════════════════════════════════
  // FÓRMULA DE PROGRESSÃO EXTREMAMENTE LENTA (v13.0)
  // ═══════════════════════════════════════════════════════════════
  // BASE: 180 * (level - 1)^2.2
  // 
  // Nível 10:  ~18.000 XP   (antes ~2.800)
  // Nível 25:  ~150.000 XP  (antes ~12.500)
  // Nível 50:  ~830.000 XP  (antes ~34.600)
  // Nível 75:  ~2.000.000 XP (antes ~64.900)
  // Nível 100: ~4.000.000 XP (antes ~98.000)
  // Nível 150: ~9.500.000 XP (antes ~181.000)
  // Nível 200: ~18.000.000 XP (antes ~278.000)
  // Nível 300: ~45.000.000 XP (antes ~516.000)
  // Nível 500: ~150.000.000 XP (antes ~1.500.000)
  // Nível 1000: ~720.000.000 XP (antes ~6.000.000)
  // Nível 2500: ~5.500.000.000 XP
  // Nível 5000: ~25.000.000.000 XP
  // Nível 10000: ~110.000.000.000 XP
  // ═══════════════════════════════════════════════════════════════
  
  const base = 180;
  const exponent = 2.2;
  const raw = base * Math.pow(level - 1, exponent);
  
  // Proteção contra overflow
  return Math.min(Math.floor(raw), Number.MAX_SAFE_INTEGER);
}

function xpForNextLevel(xp) {
  let level = 1;
  while (xpForLevel(level + 1) <= xp) level++;
  return xpForLevel(level + 1);
}

function getLevel(xp) {
  let level = 1;
  while (xpForLevel(level + 1) <= xp) level++;
  return level;
}

// ══════════════════════════════════════════════════════════════
// RECOMPENSAS DE BATALHA
// ══════════════════════════════════════════════════════════════
function calcBattleRewards(win, save) {
  // v11-balance: gold e XPP base ~15% menores (acompanhando o aumento geral de
  // preços da loja/pesca). XP de batalha ficou como estava — o ritmo de
  // progressão do Battle Pass já foi ajustado separadamente espaçando os
  // tiers e reduzindo o XP de recompensa do pass, então não precisa cortar
  // XP de batalha também.
  const baseGold = win ? 295 + Math.floor(Math.random() * 77) : 23 + Math.floor(Math.random() * 23);
  const baseXP   = win ? 108 + Math.floor(Math.random() * 54) : 23 + Math.floor(Math.random() * 18);
  const baseXPP  = win ? 670  + Math.floor(Math.random() * 8)  : 3  + Math.floor(Math.random() * 2);

  const now = Date.now();
  const boosts = save.activeBoosts || [];

  let gMult = 1, xMult = 1, xpMult = 1;
  for (const b of boosts) {
    if (b.endTime <= now) continue;
    if (b.type === "gold" || b.type === "all") gMult  = Math.max(gMult,  b.mult);
    if (b.type === "xp"   || b.type === "all") xMult  = Math.max(xMult,  b.mult);
    if (b.type === "xpp"  || b.type === "all") xpMult = Math.max(xpMult, b.mult);
  }

  // Bônus de fim de semana: XP dobrado
  const day = new Date().getDay();
  if (day === 0 || day === 6) xMult = Math.max(xMult, 2);

  return {
    gold: Math.floor(baseGold * gMult),
    xp:   Math.floor(baseXP  * xMult),
    xpp:  Math.floor(baseXPP * xpMult),
  };
}

function cleanExpiredBoosts(save) {
  if (!save.activeBoosts) { save.activeBoosts = []; return; }
  const now = Date.now();
  save.activeBoosts = save.activeBoosts.filter(b => b.endTime > now);
}

// ══════════════════════════════════════════════════════════════
// MISSÕES DIÁRIAS
// ══════════════════════════════════════════════════════════════
function getMissionProgress(save, missionId) {
  const def = { progress:0, completed:false, claimed:false };
  if (!save.dailyMissions) { save.dailyMissions = {}; }
  return save.dailyMissions[missionId] || def;
}

function updateMissionProgress(save, type) {
  if (!save.dailyMissions) save.dailyMissions = {};
  DAILY_MISSIONS.forEach(m => {
    if (m.type !== type) return;
    const state = getMissionProgress(save, m.id);
    if (state.claimed) return;
    const wasCompleted = state.completed;
    state.progress = Math.min(m.target, (state.progress || 0) + 1);
    state.completed = state.progress >= m.target;
    save.dailyMissions[m.id] = state;
    // "Complete 5 missões diárias" do Battle Pass
    if (!wasCompleted && state.completed) updatePassMissionProgress(save, "pmDaily", 1);
  });

  // "Vença 10 batalhas" e "Abra 3 pacotes" do Battle Pass
  if (type === "wins")  updatePassMissionProgress(save, "pmWins", 1);
  if (type === "packs") updatePassMissionProgress(save, "pmPacks", 1);
}

// ══════════════════════════════════════════════════════════════
// UTILIDADES
// ══════════════════════════════════════════════════════════════
function fmtNum(n) {
  n = Number(n) || 0;
  if (n >= 1e15) return (n/1e15).toFixed(1).replace(/\.0$/,"") + "Q";
  if (n >= 1e12) return (n/1e12).toFixed(1).replace(/\.0$/,"") + "T";
  if (n >= 1e9)  return (n/1e9).toFixed(1).replace(/\.0$/,"")  + "B";
  if (n >= 1e6)  return (n/1e6).toFixed(1).replace(/\.0$/,"")  + "M";
  if (n >= 1e3)  return (n/1e3).toFixed(1).replace(/\.0$/,"")  + "K";
  return String(Math.floor(n));
}

function fmtTime(ms) {
  const s = Math.floor(ms / 1000);
  const h = Math.floor(s / 3600);
  const m = Math.floor((s % 3600) / 60);
  const sec = s % 60;
  if (h > 0) return `${h}h ${m}m`;
  if (m > 0) return `${m}m ${sec}s`;
  return `${sec}s`;
}

function rarityStyle(rarity) {
  const r = RARITY[rarity];
  if (!r) return "";
  return `color:${r.color};font-weight:700;`;
}

function showToast(msg, type = "info", duration = 3200) {
  const c = document.getElementById("toast-container");
  if (!c) return;
  const t = document.createElement("div");
  t.className = `toast ${type}`;
  t.textContent = msg;
  c.appendChild(t);
  setTimeout(() => t.remove(), duration);
}

// ══════════════════════════════════════════════════════════════
// PERFIL: helpers
// ══════════════════════════════════════════════════════════════
function getProfileItemById(id) {
  if (!id) return null;
  // CREATOR_ITEMS vem do gamedata2.js (itens exclusivos de criador verificado)
  const creatorPool = (typeof CREATOR_ITEMS !== "undefined") ? CREATOR_ITEMS : [];
  return PROFILE_ITEMS.find(p => p.id === id)
      || SHOWCASE_POOL.find(p => p.id === id)
      || creatorPool.find(p => p.id === id)
      || null;
}

function hasProfileItem(save, itemId) {
  return (save.ownedProfileItems || []).includes(itemId);
}

function buildProfileCard(save) {
  const level   = getLevel(save.xp);
  const rank    = getRank(save.xpp);
  const frame   = getProfileItemById(save.profileFrame);
  const title   = getProfileItemById(save.profileTitle);
  const avatar  = getProfileItemById(save.profileAvatar);
  const effect  = getProfileItemById(save.profileEffect);
  const badge   = getProfileItemById(save.profileBadge);

  return { level, rank, frame, title, avatar, effect, badge };
}